-- ============================================================
-- seedHopeData.sql
-- M3 — Database Engineer (Sprint 1, PR-01 supplement)
--
-- Seeds the 5 HopeDB business tables with synthetic data
-- matching the Sprint 1 spec row counts.
--
-- Row counts:
--   customer:     82
--   product:      52
--   sales:       124
--   salesDetail: ~250 (varies — avg 2 line items per sale)
--   priceHist:   ~70  (varies — 1-2 entries per product)
--
-- Run order: AFTER hopeCMSTable.sql (tables must exist) and
-- AFTER alterCustomer.sql (record_status + stamp columns).
--
-- All data is deterministic — generated with seed=42.
-- Re-run is safe via TRUNCATE pattern below (optional).
-- ============================================================

-- Optional clean slate (uncomment if re-seeding):
-- TRUNCATE TABLE salesDetail, priceHist, sales, product, customer RESTART IDENTITY CASCADE;

-- ── 1. PRODUCT (52 rows) ──

-- ── 2. CUSTOMER (82 rows) ──

-- ── 3. PRICEHIST (70 rows) ──

-- ── 4. SALES (124 rows) ──

-- ── 5. SALESDETAIL (247 rows) ──

